import json
from datetime import datetime
from pathlib import Path
import subprocess

AGENTS_DIR = Path('/Users/whh073/.openclaw/agents')
TMP_DIR = Path('/tmp/memory-sync-all-agents')
TMP_DIR.mkdir(exist_ok=True, parents=True)

# 第一步：聚合所有会话按日期
date_messages = {}
for agent_dir in AGENTS_DIR.iterdir():
    if not agent_dir.is_dir() or agent_dir.name.startswith('.') or agent_dir.name.endswith('.bak'):
        continue
    sessions_dir = agent_dir / 'sessions'
    if not sessions_dir.exists():
        continue
    for jsonl in sessions_dir.glob('*.jsonl'):
        with open(jsonl, 'r', encoding='utf-8', errors='replace') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    msg = json.loads(line)
                except:
                    continue

                if 'timestamp' in msg:
                    ts = msg['timestamp']
                    try:
                        if isinstance(ts, (int, float)):
                            dt = datetime.fromtimestamp(ts / 1000 if ts > 1e12 else ts)
                        else:
                            dt = datetime.fromisoformat(ts.replace('Z', '+00:00'))
                        date_str = dt.strftime('%Y-%m-%d')
                    except:
                        mtime = jsonl.stat().st_mtime
                        dt = datetime.fromtimestamp(mtime)
                        date_str = dt.strftime('%Y-%m-%d')
                else:
                    mtime = jsonl.stat().st_mtime
                    dt = datetime.fromtimestamp(mtime)
                    date_str = dt.strftime('%Y-%m-%d')

                msg['_agent_name'] = agent_dir.name
                if date_str not in date_messages:
                    date_messages[date_str] = []
                date_messages[date_str].append(msg)

# 写出聚合后的文件
for date_str, messages in date_messages.items():
    messages.sort(key=lambda m: m.get('timestamp', 0))
    out_path = TMP_DIR / f'{date_str}.jsonl'
    with open(out_path, 'w', encoding='utf-8') as f:
        for msg in messages:
            try:
                f.write(json.dumps(msg, ensure_ascii=False) + '\\n')
            except:
                pass

print(f'✅ 聚合完成: {len(date_messages)} 个日期')
print(f'📁 输出: {TMP_DIR}')

# 第二步：对每个日期运行 backfill
SKILL_DIR = Path('/Users/whh073/.openclaw/workspace/skills/memory-sync')
MEMORY_DIR = Path('/Users/whh073/.openclaw/workspace/memory')

created = 0
already_exists = 0

for date_str in sorted(date_messages.keys()):
    out_file = MEMORY_DIR / f'{date_str}.md'
    if out_file.exists():
        already_exists += 1
        print(f'  ⏭  {date_str} 已存在，跳过')
        continue

    print(f'  🔄 处理 {date_str}...')
    cmd = [
        'python3', str(SKILL_DIR / 'memory_sync.py'),
        'backfill', '--date', date_str,
        '--sessions-dir', str(TMP_DIR)
    ]
    result = subprocess.run(cmd, capture_output=True, text=True)
    if result.returncode == 0:
        created += 1
        print(f'  ✅ {date_str} 完成')
    else:
        print(f'  ❌ {date_str} 失败: {result.stderr[:100]}')

print(f'\\n🎉 全部完成! 创建 {created} 个新文件，{already_exists} 个已存在跳过')
