    with open(out_path, 'w', encoding='utf-8') as f:
        for msg in messages:
            try:
                f.write(json.dumps(msg, ensure_ascii=False))
                f.write('\n')
            except:
                pass

print(f'\n✅ 聚合完成:')
print(f'   扫描了 {total_files} 个会话文件')
print(f'   提取了 {total_messages} 条有效消息')
print(f'   分到 {len(date_messages)} 个日期:')
for date_str in sorted(date_messages.keys()):
    print(f'     {date_str}: {len(date_messages[date_str])} 条')
