/**
 * ima-skills - 成语接龙游戏技能
 * 对接 https://ima.qq.com/api 成语接龙 API
 */

const axios = require('axios');

const CONFIG = {
  apiUrl: "https://ima.qq.com/api",
  apiKey: "SEW7vCzjMkaqYWvbSBE9Ld6E6JCnttEhkXPI9HbrGUxjydJErtxyvH4PMh6GMI1/eKRXNyuClw==", // 需要用户填入 API Key
  defaultEnabled: true
};

// 检查成语是否符合接龙规则
function checkChengyu(current, last) {
  // 最后一个字 vs 第一个字
  const lastChar = last[last.length - 1];
  const firstChar = current[0];
  return lastChar === firstChar;
}

// 主运行函数
async function run(args, context) {
  const userInput = args.userInput || '';
  const chatId = context.chatId || 'unknown';

  // 如果没有 API Key，提示用户设置
  if (!CONFIG.apiKey) {
    return {
      action: 'ask',
      question: '请先在技能配置中填入 API Key，获取方式：https://ima.qq.com/agent-interface'
    };
  }

  // 检查是否已经开始游戏，用户给出第一个成语
  const chengyuMatch = userInput.match(/([\u4e00-\u9fa5]{4})/);
  let currentChengyu = null;
  if (chengyuMatch && chengyuMatch[1].length === 4) {
    currentChengyu = chengyuMatch[1];
  }

  // 如果这是第一个成语，开始游戏
  if (currentChengyu && !context.lastChengyu) {
    // 验证成语
    try {
      const response = await axios.get(`${CONFIG.apiUrl}/check`, {
        headers: {
          'Authorization': `Bearer ${CONFIG.apiKey}`,
          'Content-Type': 'application/json'
        },
        params: {
          chengyu: currentChengyu
        }
      });

      if (response.data && response.data.valid) {
        return {
          action: 'done',
          message: `✅ 游戏开始！我接：\n\n**${response.data.next}**`,
          result: {
            started: true,
            lastChengyu: response.data.next
          }
        };
      } else {
        return {
          action: 'ask',
          question: '这个成语不在成语库中，请换一个成语重新开始。'
        };
      }
    } catch (e) {
      return {
        action: 'ask',
        question: `验证成语失败：${e.message}，请重试。`
      };
    }
  }

  // 如果已有上一个成语，用户接上了
  if (currentChengyu && context.lastChengyu) {
    // 检查接龙
    if (!checkChengyu(currentChengyu, context.lastChengyu) {
      return {
        action: 'ask',
        question: `接龙不正确！"${context.lastChengyu}" 的最后一个字是 "${context.lastChengyu[context.lastChengyu.length - 1]}"，你的成语 "${currentChengyu}" 第一个字不对，请重新接。`
      };
    }

    // 验证成语
    try {
      const response = await axios.get(`${CONFIG.apiUrl}/check`, {
        headers: {
          'Authorization': `Bearer ${CONFIG.apiKey}`,
          'Content-Type': 'application/json'
        },
        params: {
          chengyu: currentChengyu
        }
      });

