#!/usr/bin/env python3
"""
IMA-note - IMA 个人笔记技能
对接 IMA API 提供笔记服务
"""

import os
import requests
from typing import List, Dict, Any

def get_headers():
    """获取认证头"""
    client_id = os.environ.get('IMA_OPENAPI_CLIENTID')
    api_key = os.environ.get('IMA_OPENAPI_APIKEY')
    return {
        'X-Client-ID': client_id,
        'Authorization': f'Bearer {api_key}'
    }

def list_notebooks():
    """列出所有笔记本"""
    url = 'https://ima.qq.com/api/v1/notebooks'
    response = requests.get(url, headers=get_headers())
    response.raise_for_status()
    return response.json()

def search_notes(query: str, notebook: str = None):
    """搜索笔记"""
    url = 'https://ima.qq.com/api/v1/search'
    params = {'q': query}
    if notebook:
        params['notebook'] = notebook
    response = requests.get(url, params=params, headers=get_headers())
    response.raise_for_status()
    return response.json()

def get_note(note_id: str):
    """获取笔记内容"""
    url = f'https://ima.qq.com/api/v1/notes/{note_id}'
    response = requests.get(url, headers=get_headers())
    response.raise_for_status()
    return response.json()

def create_note(title: str, content: str, notebook: str = None):
    """新建笔记"""
    url = 'https://ima.qq.com/api/v1/notes'
    data = {
        'title': title,
        'content': content,
    }
    if notebook:
        data['notebook'] = notebook
    response = requests.post(url, json=data, headers=get_headers())
    response.raise_for_status()
    return response.json()

def update_note(note_id: str, title: str = None, content: str = None, notebook: str = None):
    """更新笔记"""
    url = f'https://ima.qq.com/api/v1/notes/{note_id}'
    data = {}
    if title:
        data['title'] = title
    if content:
        data['content'] = content
    if notebook:
        data['notebook'] = notebook
    response = requests.patch(url, json=data, headers=get_headers())
    response.raise_for_status()
    return response.json()

def main(args, context):
    """主入口"""
    user_input = args.get('userInput', '').lower()

    try:
        # 列出所有笔记本
        if 'list' in user_input or '列出' in user_input or '所有' in user_input:
            result = list_notebooks()
            notebooks = result.get('notebooks', [])
            if not notebooks:
                return {'action': 'done', 'message': '暂无笔记本'}

            message = '📋 你的笔记本列表:\n\n'
            for nb in notebooks:
                message += f'- **{nb["title"]}** ({nb["note_count"]} 条笔记)\n'

            return {'action': 'done', 'message': message}

        # 搜索笔记
        elif 'search' in user_input:
            # 提取查询词
            query = user_input.replace('search', '').replace('搜索', '').strip()
            if not query:
                return {'action': 'ask', 'question': '请告诉我要搜索什么关键词'}
            result = search_notes(query)
            notes = result.get('notes', [])
            if not notes:
                return {'action': 'done', 'message': f'没有找到包含 "{query}" 的笔记'}

            message = f'🔍 搜索结果 "{query}":\n\n'
            for note in notes[:10]:
                message += f'- [{note["title"]}]({note["url"]})\n'
            if len(notes) > 10:
                message += f'\n... 还有 {len(notes) - 10} 条'

            return {'action': 'done', 'message': message}

        # 默认：列出笔记本
        else:
            result = list_notebooks()
            notebooks = result.get('notebooks', [])
            if not notebooks:
                return {'action': 'done', 'message': '暂无笔记本'}

            message = '📝 IMA 笔记本列表:\n\n'
            for nb in notebooks:
                message += f'- **{nb["title"]}** ({nb["note_count"]} 条笔记)\n'

            return {'action': 'done', 'message': message}

    except Exception as e:
        return {'action': 'done', 'message': f'❌ 请求失败: {str(e)}'}

if __name__ == '__main__':
    import sys
    result = main({'userInput': ' '.join(sys.argv[1:])}, {})
    print(result['message'])
