#!/usr/bin/env python3
"""
IMA-note - IMA 个人笔记技能
对接 IMA API 提供笔记服务
"""

import os
import requests
from typing import List, Dict, Any

def get_headers():
    """获取认证头"""
    client_id = os.environ.get('IMA_OPENAPI_CLIENTID')
    api_key = os.environ.get('IMA_OPENAPI_APIKEY')
    return {
        'ima-openapi-clientid': client_id,
        'ima-openapi-apikey': api_key,
        'Content-Type': 'application/json'
    }

def list_notebooks(cursor: str = "", limit: int = 20):
    """列出所有笔记本"""
    url = 'https://ima.qq.com/openapi/note/v1/list_note_folder_by_cursor'
    data = {
        'cursor': cursor,
        'limit': limit
    }
    response = requests.post(url, json=data, headers=get_headers())
    response.raise_for_status()
    return response.json()

def search_notes(query: str, search_type: int = 0, folder_id: str = None):
    """搜索笔记"""
    url = 'https://ima.qq.com/openapi/note/v1/search_note_book'
    data = {
        'query_info': {
            'title': query if search_type == 0 else '',
            'content': query if search_type == 1 else '',
        },
        'search_type': search_type,
        'sort_type': 0,
        'start': 0,
        'end': 20,
    }
    if folder_id:
        data['folder_id'] = folder_id
    response = requests.post(url, json=data, headers=get_headers())
    response.raise_for_status()
    return response.json()

def get_note(note_id: str):
    """获取笔记内容"""
    url = 'https://ima.qq.com/openapi/note/v1/get_doc_content'
    data = {
        'doc_id': note_id,
        'target_content_format': 0,
    }
    response = requests.post(url, json=data, headers=get_headers())
    response.raise_for_status()
    return response.json()

def create_note(content: str, title: str = None, folder_id: str = None):
    """新建笔记"""
    url = 'https://ima.qq.com/openapi/note/v1/import_doc'
    data = {
        'content_format': 1,
        'content': content,
    }
    if title:
        # title 从 content 提取第一行
        pass
    if folder_id:
        data['folder_id'] = folder_id
    response = requests.post(url, json=data, headers=get_headers())
    response.raise_for_status()
    return response.json()

def append_note(note_id: str, content: str):
    """追加内容到笔记"""
    url = 'https://ima.qq.com/openapi/note/v1/append_doc'
    data = {
        'doc_id': note_id,
        'content_format': 1,
        'content': content,
    }
    response = requests.post(url, json=data, headers=get_headers())
    response.raise_for_status()
    return response.json()

def format_folders(result):
    """格式化笔记本列表输出"""
    folders = result.get('note_book_folders', [])
    if not folders:
        return "📝 暂无笔记本"

    message = "📝 你的笔记本列表:\n\n"
    for folder in folders:
        if folder.get('status', 0) != 0:
            continue
        name = folder.get('name', '未命名')
        count = folder.get('note_number', 0)
        message += f'- **{name}** ({count} 条笔记)\n'

    if not result.get('is_end', True):
        message += '\n... 还有更多'

    return message

def main(args, context):
    """主入口"""
    user_input = args.get('userInput', '').lower()

    try:
        # 列出所有笔记本
        if any(word in user_input for word in ['list', '列出', '所有', '笔记本']):
            result = list_notebooks()
            message = format_folders(result)
            return {'action': 'done', 'message': message}

        # 搜索笔记
        elif 'search' in user_input or '搜索' in user_input:
            # 提取查询词
            query = user_input.replace('search', '').replace('搜索', '笔记', '').strip()
            if not query:
                return {'action': 'ask', 'question': '请告诉我要搜索什么关键词'}
            result = search_notes(query)
            notes = result.get('docs', [])
            if not notes:
                return {'action': 'done', 'message': f'没有找到包含 "{query}" 的笔记'}

            message = f'🔍 搜索结果 "{query}":\n\n'
            for note in notes[:10]:
                basic = note.get('basic_info', {})
                title = basic.get('title', '未命名')
                docid = basic.get('docid', '')
                message += f'- [{title}](https://ima.qq.com/doc/{docid})\n'
            if len(notes) > 10:
                message += f'\n... 还有 {len(notes) - 10} 条'

            return {'action': 'done', 'message': message}

        # 默认：列出笔记本
        else:
            result = list_notebooks()
            message = format_folders(result)
            return {'action': 'done', 'message': message}

    except Exception as e:
        return {'action': 'done', 'message': f'❌ 请求失败: {str(e)}'}

if __name__ == '__main__':
    import sys
    result = main({'userInput': ' '.join(sys.argv[1:])}, {})
    print(result['message'])
